text:
{{
  (() => {
    var dropOffPercentage = Number(currentItem.drop_off_share_percentage) || 0;
    var remainingPercentage = 100 - dropOffPercentage;

    return '<div style="width:100%; padding:5px;">' +
           '<div style="display:flex; width:100%; height:30px; border:1px solid #ddd; overflow:hidden;">' +
           '<div style="width:' + dropOffPercentage + '%; height:100%; background:#ea4335; display:flex; align-items:center; justify-content:center; color:white; font-size:12px; font-weight:bold;">' +
           (dropOffPercentage > 8 ? dropOffPercentage + '%' : '') + '</div>' +
           '<div style="width:' + remainingPercentage + '%; height:100%; background:#e0e0e0; display:flex; align-items:center; justify-content:center; color:#333; font-size:12px; font-weight:bold;">' +
           (remainingPercentage > 8 ? remainingPercentage + '%' : '') + '</div>' +
           '</div>' +
           '<div style="text-align:center; margin-top:5px; font-size:11px; color:#666;">' +
           'Drop-off: ' + dropOffPercentage + '% | Beantwortet: ' + remainingPercentage + '%' +
           '</div>' +
           '</div>';
  })()
}}
